// Rerank-ordered ranking with authority tiebreak + fail-open fallback.
const queryResult = $('Search Qdrant').item.json;
const reranked = $('Rerank').item.json;
// Query API returns {result: {points: [...]}} — handle multiple response shapes
const hits = (queryResult.result && Array.isArray(queryResult.result.points))
  ? queryResult.result.points
  : (Array.isArray(queryResult.result) ? queryResult.result
    : (Array.isArray(queryResult.points) ? queryResult.points : []));
const now = new Date();

let ranked;
if (reranked && reranked.results && reranked.results.length > 0) {
  // Reranker succeeded — use rerank scores as primary sort
  ranked = reranked.results
    .map(r => {
      const h = hits[r.index];
      if (!h) return null;
      const from = h.payload?.effective_from ? new Date(h.payload.effective_from) : null;
      const to = h.payload?.effective_to ? new Date(h.payload.effective_to) : null;
      const inEffect = (!from || from <= now) && (!to || to >= now);
      return { ...h, _rerank: r.relevance_score, _inEffect: inEffect };
    })
    .filter(h => h && h._inEffect)
    .sort((a, b) => b._rerank - a._rerank);
} else {
  // Fail-open: reranker down — fall back to authority blend
  ranked = hits.map(h => {
    const authority = h.payload?.authority_weight ?? 1.0;
    const from = h.payload?.effective_from ? new Date(h.payload.effective_from) : null;
    const to = h.payload?.effective_to ? new Date(h.payload.effective_to) : null;
    const inEffect = (!from || from <= now) && (!to || to >= now);
    return { ...h, _rerank: (h.score || 0) * authority, _inEffect: inEffect };
  }).filter(h => h._inEffect).sort((a, b) => b._rerank - a._rerank);
}

// Dedup + token-budget guard (unchanged)
const MAX_CHARS = 24000;
const seen = new Set();
const top = [];
let used = 0;
for (const h of ranked) {
  const t = h.payload?.text || '';
  const k = t.slice(0, 80);
  if (seen.has(k)) continue;
  if (used + t.length > MAX_CHARS && top.length >= 1) break;
  seen.add(k); top.push(h); used += t.length;
  if (top.length >= 5) break;
}

const context = top.map((h, i) =>
  `[Source ${i+1}: ${h.payload?.doc_key} v${h.payload?.version} (${h.payload?.category})]\n${h.payload?.text}`
).join('\n\n');

const sources = top.map(h => ({
  document_id: h.payload?.document_id, doc_key: h.payload?.doc_key,
  version: h.payload?.version, category: h.payload?.category,
  score: h.score, rerank_score: h._rerank,
  authority: h.payload?.authority_weight
}));

return [{ json: { context, sources, context_chars: used } }];
